		('french_department_numbers', 'Guyane', 'reverse', 'department_name', 'À quel département correspond le numéro 973 ?', 'Guyane', array[]::text[], array[]::text[], 20),
		('french_department_numbers', 'La Réunion', 'forward', 'department_number', 'Quel est le numéro du département suivant : La Réunion ?', '974', array[]::text[], array[]::text[], 10),
		('french_department_numbers', 'La Réunion', 'reverse', 'department_name', 'À quel département correspond le numéro 974 ?', 'La Réunion', array[]::text[], array[]::text[], 20),
